// // This module implements a D flip-flop with an enable signal. The output Q captures the value of the input D on the falling edge of the clock (CLK) only when the enable signal (EN) is low.
module top_module(CLK, D, EN, Q);input CLK, D, EN;
  output Q;

  reg Q_reg;

  always @(posedge CLK) begin
    if (EN) begin
      Q_reg <= D;
    end
  end

  assign Q = Q_reg;

endmodule
